code.styles.css:
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
  font-family: "PP Editorial New";
  color: #3e3b36;
}

html,
body {
  width: 100%;
  height: 100vh;
  background: #b2b2a8;
  display: flex;
  justify-content: center;
  align-items: center;
}

.container {
  width: 100%;
  height: 100vh;
  padding: 2em;
}

.row {
  display: flex;
  justify-content: space-between;
}

.hr {
  width: 100%;
  height: 1px;
  background: #3e3b36;
}

.reveal {
  width: 500px;
  height: 140px;
  position: relative;
  overflow: hidden;
}

.reveal div {
  position: absolute;
  line-height: 1.8em;
}

.h1 {
  font-size: 6.4em;
  font-weight: 400;
  letter-spacing: -0.02em;
}

.h1 span {
  font-style: italic;
}

.secondary {
  font-family: "Neue Montreal";
}

.p {
  padding: 0.8em 0;
  font-family: "Neue Montreal";
  font-size: 12px;
  font-weight: 500;
  text-transform: uppercase;
}

.white-space {
  width: 100%;
  height: 120px;
}

.nav-item {
  width: 240px;
  border-radius: 0 0 40px 0;
  margin: 0.6em;
  display: flex;
  justify-content: space-between;
  align-items: flex-end;
}

.nav-item > div {
  padding: 1em;
  font-family: "Neue Montreal";
  font-size: 14px;
}

.about {
  background: #fcefdf;
}

.projects {
  background: #db4c44;
}

.projects > div {
  color: #fff;
}

.contact {
  background: #e7a92b;
}

.id {
  margin-right: 0.8em;
}

@media (max-width: 900px) {
  .h1 {
    font-size: 2em;
  }
  .p {
    font-size: 8px;
  }
}
